struct MatchingSolver {
    int n_left, n_right;          // 左右部节点数
    vector<vector<int>> adj;      // 邻接表
    vector<int> match_left;       // 左部匹配结果
    vector<int> match_right;      // 右部匹配结果
    vector<bool> visited;         // 访问标记

    // 初始化
    void init(int left, int right) {
        n_left = left;
        n_right = right;
        adj.assign(n_left, {});
        match_left.assign(n_left, -1);
        match_right.assign(n_right, -1);
    }

    // 添加边（根据具体问题定义匹配条件）
    void add_edge(int u, int v) {
        adj[u].push_back(v);
    }

    // DFS增广路算法（匈牙利算法核心）
    bool dfs(int u) {
        for (int v : adj[u]) {
            if (!visited[v]) {
                visited[v] = true;
                if (match_right[v] == -1 || dfs(match_right[v])) {
                    match_left[u] = v;
                    match_right[v] = u;
                    return true;
                }
            }
        }
        return false;
    }

    // 求解最大匹配
    int solve() {
        int matching = 0;
        for (int u = 0; u < n_left; ++u) {
            visited.assign(n_right, false);
            if (dfs(u)) matching++;
        }
        return matching;
    }

    // 构造方案输出（根据题目要求调整）
    vector<pair<int, int>> get_matching_pairs() {
        vector<pair<int, int>> pairs;
        for (int u = 0; u < n_left; ++u) {
            if (match_left[u] != -1) {
                pairs.emplace_back(u, match_left[u]);
            }
        }
        return pairs;
    }
};

