// 博弈贪心问题通用框架
#include <bits/stdc++.h>
using namespace std;

typedef long long ll;

// 核心分析函数：判断当前状态对先手玩家（通常是Alice）是否为必胜态
// 参数说明：
// - state: 当前游戏状态，可能是字符串、数组、数值等
// - player: 当前玩家（0=先手，1=后手），用于需要递归分析的博弈
// 返回值：bool，true表示当前玩家必胜，false表示必败
bool analyzeWinningState(auto state, int player = 0) {
    // 1. 基础情况：游戏结束状态
    if (isTerminalState(state)) {
        // 根据游戏规则判断当前玩家是否获胜
        return evaluateTerminalState(state, player);
    }

    // 2. 获取所有合法移动
    vector<auto> moves = generateAllMoves(state, player);

    // 3. 博弈树分析（根据游戏类型选择策略）
    // 类型A：完全信息零和博弈（标准博弈树）
    if (isPerfectInformationGame(state)) {
        for (auto& move : moves) {
            auto nextState = applyMove(state, move);
            if (!analyzeWinningState(nextState, player ^ 1)) {
                return true; // 存在一步使对手进入必败态
            }
        }
        return false; // 所有移动都会让对手进入必胜态
    }

    // 类型B：贪心策略博弈（常见于对称操作游戏）
    if (isGreedySymmetryGame(state)) {
        // 寻找最优贪心策略
        auto bestMove = findGreedyMove(state, player);
        // 通常需要数学证明贪心策略的最优性
        return evaluateGreedyStrategy(state, player);
    }

    // 类型C：Nim类游戏（异或和判断）
    if (isNimLikeGame(state)) {
        int xorSum = 0;
        for (auto& pile : state) {
            xorSum ^= pile.value; // 或其他关键指标
        }
        return xorSum != 0; // 异或和非零则先手必胜
    }

    // 类型D：SG函数游戏（组合博弈）
    if (isCompositeGame(state)) {
        int sg = 0;
        for (auto& subgame : decomposeState(state)) {
            sg ^= calculateSG(subgame);
        }
        return sg != 0;
    }

    // 类型E：对称策略游戏（模仿策略）
    if (isSymmetricGame(state)) {
        // 检查是否存在对称操作
        if (canMirrorOpponentMove(state)) {
            return true; // 后手模仿策略通常使先手必胜
        }
        return analyzeSpecialCases(state);
    }

    // 默认：动态规划记忆化搜索
    static map<decltype(state), bool> memo;
    if (memo.count(state)) return memo[state];

    bool canWin = false;
    for (auto& move : moves) {
        auto nextState = applyMove(state, move);
        if (!analyzeWinningState(nextState, player ^ 1)) {
            canWin = true;
            break;
        }
    }

    return memo[state] = canWin;
}

