// 1. 可行性检查函数
bool check(ll mid, vector<ll>& needs, ll total) {
    // 二分答案的检查函数
    ll sum = 0;
    for (auto need : needs) {
        sum += max(0LL, need - mid);
        if (sum > total) return false;
    }
    return true;
}

