// 3. 动态规划模板（资源分配型）
ll dp_allocation(vector<ll>& values, ll total) {
    vector<ll> dp(total + 1, 0);
    for (auto v : values) {
        for (ll j = total; j >= v; j--) {
            dp[j] = max(dp[j], dp[j - v] + v);
        }
    }
    return dp[total];
}
